import React, { useEffect, useState } from 'react';
import api from '../api';

import { Patient } from '../types';

const PatientList: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editData, setEditData] = useState<Patient | null>(null);

  useEffect(() => {
    fetchPatients();
  }, []);

  const fetchPatients = async () => {
    try {
      const response = await api.get('patients/');
      setPatients(response.data);
    } catch (err) {
      console.error("Error fetching patients:", err);
    }
  };

  const startEditing = (patient: Patient) => {
    setEditingId(patient.patient_id);
    // I-copy ang tibuok object para dili mo-error ang email/contact
    setEditData({ ...patient });
  };

  const handleUpdate = async (id: number) => {
    if (!editData) return;
    try {
      // I-send ang kompleto nga data para mawala ang 400 error
      await api.put(`patients/${id}/`, editData);
      setEditingId(null);
      fetchPatients();
    } catch (err: any) {
      console.error("Update Error:", err.response?.data);
    }
  };

  return (
    <div className="p-4">
      <h2 className="text-xl font-bold mb-4">Patient Records</h2>
      <table className="min-w-full border">
        <thead>
          <tr className="bg-gray-100">
            <th className="border p-2">Name</th>
            <th className="border p-2">Email</th>
            <th className="border p-2">Actions</th>
          </tr>
        </thead>
        <tbody>
          {patients.map((p) => (
            <tr key={p.patient_id}>
              <td className="border p-2">
                {editingId === p.patient_id ? (
                  <input 
                    className="border p-1"
                    value={editData?.first_name || ''} 
                    onChange={(e) => setEditData({ ...editData!, first_name: e.target.value })} 
                  />
                ) : (
                  `${p.first_name} ${p.last_name}`
                )}
              </td>
              <td className="border p-2">
                {editingId === p.patient_id ? (
                  <input 
                    className="border p-1"
                    value={editData?.email || ''} 
                    onChange={(e) => setEditData({ ...editData!, email: e.target.value })} 
                  />
                ) : (
                  p.email
                )}
              </td>
              <td className="border p-2">
                {editingId === p.patient_id ? (
                  <button onClick={() => handleUpdate(p.patient_id)} className="bg-green-500 text-white px-2 py-1 rounded">Save</button>
                ) : (
                  <button onClick={() => startEditing(p)} className="bg-blue-500 text-white px-2 py-1 rounded">Edit</button>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default PatientList;
